coding_challenges.solution:
// File 1: com/bank/account/Account.java
package com.bank.account;
public class Account {
    private double balance;
    public Account(double balance) { this.balance = balance; }
    public double getBalance() { return balance; }
    public void setBalance(double balance) { this.balance = balance; }
}

// File 2: com/bank/transaction/Withdrawal.java
package com.bank.transaction;
import com.bank.account.Account;
public class Withdrawal {
    public static void execute(Account acc, double amount) {
        if(acc.getBalance() >= amount) {
            acc.setBalance(acc.getBalance() - amount);
            System.out.println("Transaction successful. Remaining balance: " + acc.getBalance());
        } else {
            System.out.println("Insufficient funds.");
        }
    }
}

// File 3: com/bank/app/Main.java
package com.bank.app;
import com.bank.account.Account;
import com.bank.transaction.Withdrawal;
public class Main {
    public static void main(String[] args) {
        Account myAccount = new Account(1000);
        Withdrawal.execute(myAccount, 200);
    }
}
